howto.wire:
import { StepUpProvider } from '@/blocks/auth/use-step-up/step-up-provider';

// Create is gated behind a high-severity step-up; mount the provider once.
// The deployed create_api_key proc accepts ONLY:
//   accessLevel ∈ { 'read_only', 'full_access' }   mfaLevel ∈ { 'none', 'verified' }
// Any other value (read/write/admin, required) -> INVALID_ACCESS_LEVEL at runtime.
// createApiKey also enforces STEP_UP_REQUIRED server-side: a verifyPassword on the
// SAME session must precede the create. The dialog runs that step-up first; if you
// call createApiKey directly, complete step-up (verifyPassword) before the mutation.
<StepUpProvider>{children}</StepUpProvider>

